"""
Parameterized generator for GH700_httprouter_261.

Source PR:    https://github.com/julienschmidt/httprouter/pull/261
Source Issue: N/A

Seed varies: renames 'allowed' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH700_httprouter_261'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH700_httprouter_261'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('allowed', 'allowed' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH700_httprouter_261',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'julienschmidt/httprouter',
                "pr_number": 261,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/julienschmidt/httprouter/pull/261",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'tree.go': '// Copyright 2013 Julien Schmidt. All rights reserved.\n// Use of this source code is governed by a BSD-style license that can be found\n// in the LICENSE file.\n\npackage httprouter\n\nimport (\n\t"strings"\n\t"unicode"\n\t"unicode/utf8"\n)\n\nfunc min(a, b int) int {\n\tif a <= b {\n\t\treturn a\n\t}\n\treturn b\n}\n\nconst maxParamCount uint8 = ^uint8(0)\n\nfunc countParams(path string) uint8 {\n\tvar n uint\n\tfor i := 0; i < len(path); i++ {\n\t\tif path[i] != \':\' && path[i] != \'*\' {\n\t\t\tcontinue\n\t\t}\n\t\tn++\n\t}\n\tif n >= uint(maxParamCount) {\n\t\treturn maxParamCount\n\t}\n\n\treturn uint8(n)\n}\n\ntype nodeType uint8\n\nconst (\n\tstatic nodeType = iota // default\n\troot\n\tparam\n\tcatchAll\n)\n\ntype node struct {\n\tpath      string\n\twildChild bool\n\tnType     nodeType\n\tmaxParams uint8\n\tindices   string\n\tchildren  []*node\n\thandle    Handle\n\tpriority  uint32\n}\n\n// increments priority of the given child and reorders if necessary\nfunc (n *node) incrementChildPrio(pos int) int {\n\tn.children[pos].priority++\n\tprio := n.children[pos].priority\n\n\t// adjust position (move to front)\n\tnewPos := pos\n\tfor newPos > 0 && n.children[newPos-1].priority < prio {\n\t\t// swap node positions\n\t\tn.children[newPos-1], n.children[newPos] = n.children[newPos], n.children[newPos-1]\n\n\t\tnewPos--\n\t}\n\n\t// build new index char string\n\tif newPos != pos {\n\t\tn.indices = n.indices[:newPos] + // unchanged prefix, might be empty\n\t\t\tn.indices[pos:pos+1] + // the index char we move\n\t\t\tn.indices[newPos:pos] + n.indices[pos+1:] // rest without char at \'pos\'\n\t}\n\n\treturn newPos\n}\n\n// addRoute adds a node with the given handle to the path.\n// Not concurrency-safe!\nfunc (n *node) addRoute(path string, handle Handle) {\n\tfullPath := path\n\tn.priority++\n\tnumParams := countParams(path)\n\n\t// non-empty tree\n\tif len(n.path) > 0 || len(n.children) > 0 {\n\twalk:\n\t\tfor {\n\t\t\t// Update maxParams of the current node\n\t\t\tif numParams > n.maxParams {\n\t\t\t\tn.maxParams = numParams\n\t\t\t}\n\n\t\t\t// Find the longest common prefix.\n\t\t\t// This also implies that the common prefix contains no \':\' or \'*\'\n\t\t\t// since the existing key can\'t contain those chars.\n\t\t\ti := 0\n\t\t\tmax := min(len(path), len(n.path))\n\t\t\tfor i < max && path[i] == n.path[i] {\n\t\t\t\ti++\n\t\t\t}\n\n\t\t\t// Split edge\n\t\t\tif i < len(n.path) {\n\t\t\t\tchild := node{\n\t\t\t\t\tpath:      n.path[i:],\n\t\t\t\t\twildChild: n.wildChild,\n\t\t\t\t\tnType:     static,\n\t\t\t\t\tindices:   n.indices,\n\t\t\t\t\tchildren:  n.children,\n\t\t\t\t\thandle:    n.handle,\n\t\t\t\t\tpriority:  n.priority - 1,\n\t\t\t\t}\n\n\t\t\t\t// Update maxParams (max of all children)\n\t\t\t\tfor i := range child.children {\n\t\t\t\t\tif child.children[i].maxParams > child.maxParams {\n\t\t\t\t\t\tchild.maxParams = child.children[i].maxParams\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\tn.children = []*node{&child}\n\t\t\t\t// []byte for proper unicode char conversion, see #65\n\t\t\t\tn.indices = string([]byte{n.path[i]})\n\t\t\t\tn.path = path[:i]\n\t\t\t\tn.handle = nil\n\t\t\t\tn.wildChild = false\n\t\t\t}\n\n\t\t\t// Make new node a child of this node\n\t\t\tif i < len(path) {\n\t\t\t\tpath = path[i:]\n\n\t\t\t\tif n.wildChild {\n\t\t\t\t\tn = n.children[0]\n\t\t\t\t\tn.priority++\n\n\t\t\t\t\t// Update maxParams of the child node\n\t\t\t\t\tif numParams > n.maxParams {\n\t\t\t\t\t\tn.maxParams = numParams\n\t\t\t\t\t}\n\t\t\t\t\tnumParams--\n\n\t\t\t\t\t// Check if the wildcard matches\n\t\t\t\t\tif len(path) >= len(n.path) && n.path == path[:len(n.path)] &&\n\t\t\t\t\t\t// Check for longer wildcard, e.g. :name and :names\n\t\t\t\t\t\t(len(n.path) >= len(path) || path[len(n.path)] == \'/\') {\n\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t} else {\n\t\t\t\t\t\t// Wildcard conflict\n\t\t\t\t\t\tvar pathSeg string\n\t\t\t\t\t\tif n.nType == catchAll {\n\t\t\t\t\t\t\tpathSeg = path\n\t\t\t\t\t\t} else {\n\t\t\t\t\t\t\tpathSeg = strings.SplitN(path, "/", 2)[0]\n\t\t\t\t\t\t}\n\t\t\t\t\t\tprefix := fullPath[:strings.Index(fullPath, pathSeg)] + n.path\n\t\t\t\t\t\tpanic("\'" + pathSeg +\n\t\t\t\t\t\t\t"\' in new path \'" + fullPath +\n\t\t\t\t\t\t\t"\' conflicts with existing wildcard \'" + n.path +\n\t\t\t\t\t\t\t"\' in existing prefix \'" + prefix +\n\t\t\t\t\t\t\t"\'")\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\tc := path[0]\n\n\t\t\t\t// slash after param\n\t\t\t\tif n.nType == param && c == \'/\' && len(n.children) == 1 {\n\t\t\t\t\tn = n.children[0]\n\t\t\t\t\tn.priority++\n\t\t\t\t\tcontinue walk\n\t\t\t\t}\n\n\t\t\t\t// Check if a child with the next path byte exists\n\t\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\t\tif c == n.indices[i] {\n\t\t\t\t\t\ti = n.incrementChildPrio(i)\n\t\t\t\t\t\tn = n.children[i]\n\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\t// Otherwise insert it\n\t\t\t\tif c != \':\' && c != \'*\' {\n\t\t\t\t\t// []byte for proper unicode char conversion, see #65\n\t\t\t\t\tn.indices += string([]byte{c})\n\t\t\t\t\tchild := &node{\n\t\t\t\t\t\tmaxParams: numParams,\n\t\t\t\t\t}\n\t\t\t\t\tn.children = append(n.children, child)\n\t\t\t\t\tn.incrementChildPrio(len(n.indices) - 1)\n\t\t\t\t\tn = child\n\t\t\t\t}\n\t\t\t\tn.insertChild(numParams, path, fullPath, handle)\n\t\t\t\treturn\n\n\t\t\t} else if i == len(path) { // Make node a (in-path) leaf\n\t\t\t\tif n.handle != nil {\n\t\t\t\t\tpanic("a handle is already registered for path \'" + fullPath + "\'")\n\t\t\t\t}\n\t\t\t\tn.handle = handle\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t} else { // Empty tree\n\t\tn.insertChild(numParams, path, fullPath, handle)\n\t\tn.nType = root\n\t}\n}\n\nfunc (n *node) insertChild(numParams uint8, path, fullPath string, handle Handle) {\n\tvar offset int // already handled bytes of the path\n\n\t// find prefix until first wildcard (beginning with \':\'\' or \'*\'\')\n\tfor i, max := 0, len(path); numParams > 0; i++ {\n\t\tc := path[i]\n\t\tif c != \':\' && c != \'*\' {\n\t\t\tcontinue\n\t\t}\n\n\t\t// find wildcard end (either \'/\' or path end)\n\t\tend := i + 1\n\t\tfor end < max && path[end] != \'/\' {\n\t\t\tswitch path[end] {\n\t\t\t// the wildcard name must not contain \':\' and \'*\'\n\t\t\tcase \':\', \'*\':\n\t\t\t\tpanic("only one wildcard per path segment is allowed, has: \'" +\n\t\t\t\t\tpath[i:] + "\' in path \'" + fullPath + "\'")\n\t\t\tdefault:\n\t\t\t\tend++\n\t\t\t}\n\t\t}\n\n\t\t// check if this Node existing children which would be\n\t\t// unreachable if we insert the wildcard here\n\t\tif len(n.children) > 0 {\n\t\t\tpanic("wildcard route \'" + path[i:end] +\n\t\t\t\t"\' conflicts with existing children in path \'" + fullPath + "\'")\n\t\t}\n\n\t\t// check if the wildcard has a name\n\t\tif end-i < 2 {\n\t\t\tpanic("wildcards must be named with a non-empty name in path \'" + fullPath + "\'")\n\t\t}\n\n\t\tif c == \':\' { // param\n\t\t\t// split path at the beginning of the wildcard\n\t\t\tif i > 0 {\n\t\t\t\tn.path = path[offset:i]\n\t\t\t\toffset = i\n\t\t\t}\n\n\t\t\tchild := &node{\n\t\t\t\tnType:     param,\n\t\t\t\tmaxParams: numParams,\n\t\t\t}\n\t\t\tn.children = []*node{child}\n\t\t\tn.wildChild = true\n\t\t\tn = child\n\t\t\tn.priority++\n\t\t\tnumParams--\n\n\t\t\t// if the path doesn\'t end with the wildcard, then there\n\t\t\t// will be another non-wildcard subpath starting with \'/\'\n\t\t\tif end < max {\n\t\t\t\tn.path = path[offset:end]\n\t\t\t\toffset = end\n\n\t\t\t\tchild := &node{\n\t\t\t\t\tmaxParams: numParams,\n\t\t\t\t\tpriority:  1,\n\t\t\t\t}\n\t\t\t\tn.children = []*node{child}\n\t\t\t\tn = child\n\t\t\t}\n\n\t\t} else { // catchAll\n\t\t\tif end != max || numParams > 1 {\n\t\t\t\tpanic("catch-all routes are only allowed at the end of the path in path \'" + fullPath + "\'")\n\t\t\t}\n\n\t\t\tif len(n.path) > 0 && n.path[len(n.path)-1] == \'/\' {\n\t\t\t\tpanic("catch-all conflicts with existing handle for the path segment root in path \'" + fullPath + "\'")\n\t\t\t}\n\n\t\t\t// currently fixed width 1 for \'/\'\n\t\t\ti--\n\t\t\tif path[i] != \'/\' {\n\t\t\t\tpanic("no / before catch-all in path \'" + fullPath + "\'")\n\t\t\t}\n\n\t\t\tn.path = path[offset:i]\n\n\t\t\t// first node: catchAll node with empty path\n\t\t\tchild := &node{\n\t\t\t\twildChild: true,\n\t\t\t\tnType:     catchAll,\n\t\t\t\tmaxParams: 1,\n\t\t\t}\n\t\t\tn.children = []*node{child}\n\t\t\tn.indices = string(path[i])\n\t\t\tn = child\n\t\t\tn.priority++\n\n\t\t\t// second node: node holding the variable\n\t\t\tchild = &node{\n\t\t\t\tpath:      path[i:],\n\t\t\t\tnType:     catchAll,\n\t\t\t\tmaxParams: 1,\n\t\t\t\thandle:    handle,\n\t\t\t\tpriority:  1,\n\t\t\t}\n\t\t\tn.children = []*node{child}\n\n\t\t\treturn\n\t\t}\n\t}\n\n\t// insert remaining path part and handle to the leaf\n\tn.path = path[offset:]\n\tn.handle = handle\n}\n\n// Returns the handle registered with the given path (key). The values of\n// wildcards are saved to a map.\n// If no handle can be found, a TSR (trailing slash redirect) recommendation is\n// made if a handle exists with an extra (without the) trailing slash for the\n// given path.\nfunc (n *node) getValue(path string) (handle Handle, p Params, tsr bool) {\nwalk: // outer loop for walking the tree\n\tfor {\n\t\tif len(path) > len(n.path) {\n\t\t\tif path[:len(n.path)] == n.path {\n\t\t\t\tpath = path[len(n.path):]\n\t\t\t\t// If this node does not have a wildcard (param or catchAll)\n\t\t\t\t// child,  we can just look up the next child node and continue\n\t\t\t\t// to walk down the tree\n\t\t\t\tif !n.wildChild {\n\t\t\t\t\tc := path[0]\n\t\t\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\t\t\tif c == n.indices[i] {\n\t\t\t\t\t\t\tn = n.children[i]\n\t\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\n\t\t\t\t\t// Nothing found.\n\t\t\t\t\t// We can recommend to redirect to the same URL without a\n\t\t\t\t\t// trailing slash if a leaf exists for that path.\n\t\t\t\t\ttsr = (path == "/" && n.handle != nil)\n\t\t\t\t\treturn\n\n\t\t\t\t}\n\n\t\t\t\t// handle wildcard child\n\t\t\t\tn = n.children[0]\n\t\t\t\tswitch n.nType {\n\t\t\t\tcase param:\n\t\t\t\t\t// find param end (either \'/\' or path end)\n\t\t\t\t\tend := 0\n\t\t\t\t\tfor end < len(path) && path[end] != \'/\' {\n\t\t\t\t\t\tend++\n\t\t\t\t\t}\n\n\t\t\t\t\t// save param value\n\t\t\t\t\tif p == nil {\n\t\t\t\t\t\t// lazy allocation\n\t\t\t\t\t\tp = make(Params, 0, n.maxParams)\n\t\t\t\t\t}\n\t\t\t\t\ti := len(p)\n\t\t\t\t\tp = p[:i+1] // expand slice within preallocated capacity\n\t\t\t\t\tp[i].Key = n.path[1:]\n\t\t\t\t\tp[i].Value = path[:end]\n\n\t\t\t\t\t// we need to go deeper!\n\t\t\t\t\tif end < len(path) {\n\t\t\t\t\t\tif len(n.children) > 0 {\n\t\t\t\t\t\t\tpath = path[end:]\n\t\t\t\t\t\t\tn = n.children[0]\n\t\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t\t}\n\n\t\t\t\t\t\t// ... but we can\'t\n\t\t\t\t\t\ttsr = (len(path) == end+1)\n\t\t\t\t\t\treturn\n\t\t\t\t\t}\n\n\t\t\t\t\tif handle = n.handle; handle != nil {\n\t\t\t\t\t\treturn\n\t\t\t\t\t} else if len(n.children) == 1 {\n\t\t\t\t\t\t// No handle found. Check if a handle for this path + a\n\t\t\t\t\t\t// trailing slash exists for TSR recommendation\n\t\t\t\t\t\tn = n.children[0]\n\t\t\t\t\t\ttsr = (n.path == "/" && n.handle != nil)\n\t\t\t\t\t}\n\n\t\t\t\t\treturn\n\n\t\t\t\tcase catchAll:\n\t\t\t\t\t// save param value\n\t\t\t\t\tif p == nil {\n\t\t\t\t\t\t// lazy allocation\n\t\t\t\t\t\tp = make(Params, 0, n.maxParams)\n\t\t\t\t\t}\n\t\t\t\t\ti := len(p)\n\t\t\t\t\tp = p[:i+1] // expand slice within preallocated capacity\n\t\t\t\t\tp[i].Key = n.path[2:]\n\t\t\t\t\tp[i].Value = path\n\n\t\t\t\t\thandle = n.handle\n\t\t\t\t\treturn\n\n\t\t\t\tdefault:\n\t\t\t\t\tpanic("invalid node type")\n\t\t\t\t}\n\t\t\t}\n\t\t} else if path == n.path {\n\t\t\t// We should have reached the node containing the handle.\n\t\t\t// Check if this node has a handle registered.\n\t\t\tif handle = n.handle; handle != nil {\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\tif path == "/" && n.wildChild && n.nType != root {\n\t\t\t\ttsr = true\n\t\t\t\treturn\n\t\t\t}\n\n\t\t\t// No handle found. Check if a handle for this path + a\n\t\t\t// trailing slash exists for trailing slash recommendation\n\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\tif n.indices[i] == \'/\' {\n\t\t\t\t\tn = n.children[i]\n\t\t\t\t\ttsr = (len(n.path) == 1 && n.handle != nil) ||\n\t\t\t\t\t\t(n.nType == catchAll && n.children[0].handle != nil)\n\t\t\t\t\treturn\n\t\t\t\t}\n\t\t\t}\n\n\t\t\treturn\n\t\t}\n\n\t\t// Nothing found. We can recommend to redirect to the same URL with an\n\t\t// extra trailing slash if a leaf exists for that path\n\t\ttsr = (path == "/") ||\n\t\t\t(len(n.path) == len(path)+1 && n.path[len(path)] == \'/\' &&\n\t\t\t\tpath == n.path[:len(n.path)-1] && n.handle != nil)\n\t\treturn\n\t}\n}\n\n// Makes a case-insensitive lookup of the given path and tries to find a handler.\n// It can optionally also fix trailing slashes.\n// It returns the case-corrected path and a bool indicating whether the lookup\n// was successful.\nfunc (n *node) findCaseInsensitivePath(path string, fixTrailingSlash bool) (ciPath []byte, found bool) {\n\treturn n.findCaseInsensitivePathRec(\n\t\tpath,\n\t\tmake([]byte, 0, len(path)+1), // preallocate enough memory for new path\n\t\t[4]byte{},                    // empty rune buffer\n\t\tfixTrailingSlash,\n\t)\n}\n\n// shift bytes in array by n bytes left\nfunc shiftNRuneBytes(rb [4]byte, n int) [4]byte {\n\tswitch n {\n\tcase 0:\n\t\treturn rb\n\tcase 1:\n\t\treturn [4]byte{rb[1], rb[2], rb[3], 0}\n\tcase 2:\n\t\treturn [4]byte{rb[2], rb[3]}\n\tcase 3:\n\t\treturn [4]byte{rb[3]}\n\tdefault:\n\t\treturn [4]byte{}\n\t}\n}\n\n// recursive case-insensitive lookup function used by n.findCaseInsensitivePath\nfunc (n *node) findCaseInsensitivePathRec(path string, ciPath []byte, rb [4]byte, fixTrailingSlash bool) ([]byte, bool) {\n\tnpLen := len(n.path)\n\nwalk: // outer loop for walking the tree\n\tfor len(path) >= npLen && (npLen == 0 || strings.EqualFold(path[1:npLen], n.path[1:])) {\n\t\t// add common prefix to result\n\n\t\toldPath := path\n\t\tpath = path[npLen:]\n\t\tciPath = append(ciPath, n.path...)\n\n\t\tif len(path) > 0 {\n\t\t\t// If this node does not have a wildcard (param or catchAll) child,\n\t\t\t// we can just look up the next child node and continue to walk down\n\t\t\t// the tree\n\t\t\tif !n.wildChild {\n\t\t\t\t// skip rune bytes already processed\n\t\t\t\trb = shiftNRuneBytes(rb, npLen)\n\n\t\t\t\tif rb[0] != 0 {\n\t\t\t\t\t// old rune not finished\n\t\t\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\t\t\tif n.indices[i] == rb[0] {\n\t\t\t\t\t\t\t// continue with child node\n\t\t\t\t\t\t\tn = n.children[i]\n\t\t\t\t\t\t\tnpLen = len(n.path)\n\t\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\t\t\t\t} else {\n\t\t\t\t\t// process a new rune\n\t\t\t\t\tvar rv rune\n\n\t\t\t\t\t// find rune start\n\t\t\t\t\t// runes are up to 4 byte long,\n\t\t\t\t\t// -4 would definitely be another rune\n\t\t\t\t\tvar off int\n\t\t\t\t\tfor max := min(npLen, 3); off < max; off++ {\n\t\t\t\t\t\tif i := npLen - off; utf8.RuneStart(oldPath[i]) {\n\t\t\t\t\t\t\t// read rune from cached path\n\t\t\t\t\t\t\trv, _ = utf8.DecodeRuneInString(oldPath[i:])\n\t\t\t\t\t\t\tbreak\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\n\t\t\t\t\t// calculate lowercase bytes of current rune\n\t\t\t\t\tlo := unicode.ToLower(rv)\n\t\t\t\t\tutf8.EncodeRune(rb[:], lo)\n\n\t\t\t\t\t// skip already processed bytes\n\t\t\t\t\trb = shiftNRuneBytes(rb, off)\n\n\t\t\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\t\t\t// lowercase matches\n\t\t\t\t\t\tif n.indices[i] == rb[0] {\n\t\t\t\t\t\t\t// must use a recursive approach since both the\n\t\t\t\t\t\t\t// uppercase byte and the lowercase byte might exist\n\t\t\t\t\t\t\t// as an index\n\t\t\t\t\t\t\tif out, found := n.children[i].findCaseInsensitivePathRec(\n\t\t\t\t\t\t\t\tpath, ciPath, rb, fixTrailingSlash,\n\t\t\t\t\t\t\t); found {\n\t\t\t\t\t\t\t\treturn out, true\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t\tbreak\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\n\t\t\t\t\t// if we found no match, the same for the uppercase rune,\n\t\t\t\t\t// if it differs\n\t\t\t\t\tif up := unicode.ToUpper(rv); up != lo {\n\t\t\t\t\t\tutf8.EncodeRune(rb[:], up)\n\t\t\t\t\t\trb = shiftNRuneBytes(rb, off)\n\n\t\t\t\t\t\tfor i, c := 0, rb[0]; i < len(n.indices); i++ {\n\t\t\t\t\t\t\t// uppercase matches\n\t\t\t\t\t\t\tif n.indices[i] == c {\n\t\t\t\t\t\t\t\t// continue with child node\n\t\t\t\t\t\t\t\tn = n.children[i]\n\t\t\t\t\t\t\t\tnpLen = len(n.path)\n\t\t\t\t\t\t\t\tcontinue walk\n\t\t\t\t\t\t\t}\n\t\t\t\t\t\t}\n\t\t\t\t\t}\n\t\t\t\t}\n\n\t\t\t\t// Nothing found. We can recommend to redirect to the same URL\n\t\t\t\t// without a trailing slash if a leaf exists for that path\n\t\t\t\treturn ciPath, (fixTrailingSlash && path == "/" && n.handle != nil)\n\t\t\t}\n\n\t\t\tn = n.children[0]\n\t\t\tswitch n.nType {\n\t\t\tcase param:\n\t\t\t\t// find param end (either \'/\' or path end)\n\t\t\t\tk := 0\n\t\t\t\tfor k < len(path) && path[k] != \'/\' {\n\t\t\t\t\tk++\n\t\t\t\t}\n\n\t\t\t\t// add param value to case insensitive path\n\t\t\t\tciPath = append(ciPath, path[:k]...)\n\n\t\t\t\t// we need to go deeper!\n\t\t\t\tif k < len(path) {\n\t\t\t\t\tif len(n.children) > 0 {\n\t\t\t\t\t\t// continue with child node\n\t\t\t\t\t\tn = n.children[0]\n\t\t\t\t\t\tnpLen = len(n.path)\n\t\t\t\t\t\tpath = path[k:]\n\t\t\t\t\t\tcontinue\n\t\t\t\t\t}\n\n\t\t\t\t\t// ... but we can\'t\n\t\t\t\t\tif fixTrailingSlash && len(path) == k+1 {\n\t\t\t\t\t\treturn ciPath, true\n\t\t\t\t\t}\n\t\t\t\t\treturn ciPath, false\n\t\t\t\t}\n\n\t\t\t\tif n.handle != nil {\n\t\t\t\t\treturn ciPath, true\n\t\t\t\t} else if fixTrailingSlash && len(n.children) == 1 {\n\t\t\t\t\t// No handle found. Check if a handle for this path + a\n\t\t\t\t\t// trailing slash exists\n\t\t\t\t\tn = n.children[0]\n\t\t\t\t\tif n.path == "/" && n.handle != nil {\n\t\t\t\t\t\treturn append(ciPath, \'/\'), true\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\treturn ciPath, false\n\n\t\t\tcase catchAll:\n\t\t\t\treturn append(ciPath, path...), true\n\n\t\t\tdefault:\n\t\t\t\tpanic("invalid node type")\n\t\t\t}\n\t\t} else {\n\t\t\t// We should have reached the node containing the handle.\n\t\t\t// Check if this node has a handle registered.\n\t\t\tif n.handle != nil {\n\t\t\t\treturn ciPath, true\n\t\t\t}\n\n\t\t\t// No handle found.\n\t\t\t// Try to fix the path by adding a trailing slash\n\t\t\tif fixTrailingSlash {\n\t\t\t\tfor i := 0; i < len(n.indices); i++ {\n\t\t\t\t\tif n.indices[i] == \'/\' {\n\t\t\t\t\t\tn = n.children[i]\n\t\t\t\t\t\tif (len(n.path) == 1 && n.handle != nil) ||\n\t\t\t\t\t\t\t(n.nType == catchAll && n.children[0].handle != nil) {\n\t\t\t\t\t\t\treturn append(ciPath, \'/\'), true\n\t\t\t\t\t\t}\n\t\t\t\t\t\treturn ciPath, false\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t}\n\t\t\treturn ciPath, false\n\t\t}\n\t}\n\n\t// Nothing found.\n\t// Try to fix the path by adding / removing a trailing slash\n\tif fixTrailingSlash {\n\t\tif path == "/" {\n\t\t\treturn ciPath, true\n\t\t}\n\t\tif len(path)+1 == npLen && n.path[len(path)] == \'/\' &&\n\t\t\tstrings.EqualFold(path[1:], n.path[1:len(path)]) && n.handle != nil {\n\t\t\treturn append(ciPath, n.path...), true\n\t\t}\n\t}\n\treturn ciPath, false\n}\n',
            'tree_test.go': '// Copyright 2013 Julien Schmidt. All rights reserved.\n// Use of this source code is governed by a BSD-style license that can be found\n// in the LICENSE file.\n\npackage httprouter\n\nimport (\n\t"fmt"\n\t"net/http"\n\t"reflect"\n\t"regexp"\n\t"strings"\n\t"testing"\n)\n\nfunc printChildren(n *node, prefix string) {\n\tfmt.Printf(" %02d:%02d %s%s[%d] %v %t %d \\r\\n", n.priority, n.maxParams, prefix, n.path, len(n.children), n.handle, n.wildChild, n.nType)\n\tfor l := len(n.path); l > 0; l-- {\n\t\tprefix += " "\n\t}\n\tfor _, child := range n.children {\n\t\tprintChildren(child, prefix)\n\t}\n}\n\n// Used as a workaround since we can\'t compare functions or their addresses\nvar fakeHandlerValue string\n\nfunc fakeHandler(val string) Handle {\n\treturn func(http.ResponseWriter, *http.Request, Params) {\n\t\tfakeHandlerValue = val\n\t}\n}\n\ntype testRequests []struct {\n\tpath       string\n\tnilHandler bool\n\troute      string\n\tps         Params\n}\n\nfunc checkRequests(t *testing.T, tree *node, requests testRequests) {\n\tfor _, request := range requests {\n\t\thandler, ps, _ := tree.getValue(request.path)\n\n\t\tif handler == nil {\n\t\t\tif !request.nilHandler {\n\t\t\t\tt.Errorf("handle mismatch for route \'%s\': Expected non-nil handle", request.path)\n\t\t\t}\n\t\t} else if request.nilHandler {\n\t\t\tt.Errorf("handle mismatch for route \'%s\': Expected nil handle", request.path)\n\t\t} else {\n\t\t\thandler(nil, nil, nil)\n\t\t\tif fakeHandlerValue != request.route {\n\t\t\t\tt.Errorf("handle mismatch for route \'%s\': Wrong handle (%s != %s)", request.path, fakeHandlerValue, request.route)\n\t\t\t}\n\t\t}\n\n\t\tif !reflect.DeepEqual(ps, request.ps) {\n\t\t\tt.Errorf("Params mismatch for route \'%s\'", request.path)\n\t\t}\n\t}\n}\n\nfunc checkPriorities(t *testing.T, n *node) uint32 {\n\tvar prio uint32\n\tfor i := range n.children {\n\t\tprio += checkPriorities(t, n.children[i])\n\t}\n\n\tif n.handle != nil {\n\t\tprio++\n\t}\n\n\tif n.priority != prio {\n\t\tt.Errorf(\n\t\t\t"priority mismatch for node \'%s\': is %d, should be %d",\n\t\t\tn.path, n.priority, prio,\n\t\t)\n\t}\n\n\treturn prio\n}\n\nfunc checkMaxParams(t *testing.T, n *node) uint8 {\n\tvar maxParams uint8\n\tfor i := range n.children {\n\t\tparams := checkMaxParams(t, n.children[i])\n\t\tif params > maxParams {\n\t\t\tmaxParams = params\n\t\t}\n\t}\n\tif n.nType > root && !n.wildChild {\n\t\tmaxParams++\n\t}\n\n\tif n.maxParams != maxParams {\n\t\tt.Errorf(\n\t\t\t"maxParams mismatch for node \'%s\': is %d, should be %d",\n\t\t\tn.path, n.maxParams, maxParams,\n\t\t)\n\t}\n\n\treturn maxParams\n}\n\nfunc TestCountParams(t *testing.T) {\n\tif countParams("/path/:param1/static/*catch-all") != 2 {\n\t\tt.Fail()\n\t}\n\tif countParams(strings.Repeat("/:param", 256)) != 255 {\n\t\tt.Fail()\n\t}\n}\n\nfunc TestTreeAddAndGet(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/hi",\n\t\t"/contact",\n\t\t"/co",\n\t\t"/c",\n\t\t"/a",\n\t\t"/ab",\n\t\t"/doc/",\n\t\t"/doc/go_faq.html",\n\t\t"/doc/go1.html",\n\t\t"/α",\n\t\t"/β",\n\t}\n\tfor _, route := range routes {\n\t\ttree.addRoute(route, fakeHandler(route))\n\t}\n\n\t//printChildren(tree, "")\n\n\tcheckRequests(t, tree, testRequests{\n\t\t{"/a", false, "/a", nil},\n\t\t{"/", true, "", nil},\n\t\t{"/hi", false, "/hi", nil},\n\t\t{"/contact", false, "/contact", nil},\n\t\t{"/co", false, "/co", nil},\n\t\t{"/con", true, "", nil},  // key mismatch\n\t\t{"/cona", true, "", nil}, // key mismatch\n\t\t{"/no", true, "", nil},   // no matching child\n\t\t{"/ab", false, "/ab", nil},\n\t\t{"/α", false, "/α", nil},\n\t\t{"/β", false, "/β", nil},\n\t})\n\n\tcheckPriorities(t, tree)\n\tcheckMaxParams(t, tree)\n}\n\nfunc TestTreeWildcard(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/",\n\t\t"/cmd/:tool/:sub",\n\t\t"/cmd/:tool/",\n\t\t"/src/*filepath",\n\t\t"/search/",\n\t\t"/search/:query",\n\t\t"/user_:name",\n\t\t"/user_:name/about",\n\t\t"/files/:dir/*filepath",\n\t\t"/doc/",\n\t\t"/doc/go_faq.html",\n\t\t"/doc/go1.html",\n\t\t"/info/:user/public",\n\t\t"/info/:user/project/:project",\n\t}\n\tfor _, route := range routes {\n\t\ttree.addRoute(route, fakeHandler(route))\n\t}\n\n\t//printChildren(tree, "")\n\n\tcheckRequests(t, tree, testRequests{\n\t\t{"/", false, "/", nil},\n\t\t{"/cmd/test/", false, "/cmd/:tool/", Params{Param{"tool", "test"}}},\n\t\t{"/cmd/test", true, "", Params{Param{"tool", "test"}}},\n\t\t{"/cmd/test/3", false, "/cmd/:tool/:sub", Params{Param{"tool", "test"}, Param{"sub", "3"}}},\n\t\t{"/src/", false, "/src/*filepath", Params{Param{"filepath", "/"}}},\n\t\t{"/src/some/file.png", false, "/src/*filepath", Params{Param{"filepath", "/some/file.png"}}},\n\t\t{"/search/", false, "/search/", nil},\n\t\t{"/search/someth!ng+in+ünìcodé", false, "/search/:query", Params{Param{"query", "someth!ng+in+ünìcodé"}}},\n\t\t{"/search/someth!ng+in+ünìcodé/", true, "", Params{Param{"query", "someth!ng+in+ünìcodé"}}},\n\t\t{"/user_gopher", false, "/user_:name", Params{Param{"name", "gopher"}}},\n\t\t{"/user_gopher/about", false, "/user_:name/about", Params{Param{"name", "gopher"}}},\n\t\t{"/files/js/inc/framework.js", false, "/files/:dir/*filepath", Params{Param{"dir", "js"}, Param{"filepath", "/inc/framework.js"}}},\n\t\t{"/info/gordon/public", false, "/info/:user/public", Params{Param{"user", "gordon"}}},\n\t\t{"/info/gordon/project/go", false, "/info/:user/project/:project", Params{Param{"user", "gordon"}, Param{"project", "go"}}},\n\t})\n\n\tcheckPriorities(t, tree)\n\tcheckMaxParams(t, tree)\n}\n\nfunc catchPanic(testFunc func()) (recv interface{}) {\n\tdefer func() {\n\t\trecv = recover()\n\t}()\n\n\ttestFunc()\n\treturn\n}\n\ntype testRoute struct {\n\tpath     string\n\tconflict bool\n}\n\nfunc testRoutes(t *testing.T, routes []testRoute) {\n\ttree := &node{}\n\n\tfor _, route := range routes {\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route.path, nil)\n\t\t})\n\n\t\tif route.conflict {\n\t\t\tif recv == nil {\n\t\t\t\tt.Errorf("no panic for conflicting route \'%s\'", route.path)\n\t\t\t}\n\t\t} else if recv != nil {\n\t\t\tt.Errorf("unexpected panic for route \'%s\': %v", route.path, recv)\n\t\t}\n\t}\n\n\t//printChildren(tree, "")\n}\n\nfunc TestTreeWildcardConflict(t *testing.T) {\n\troutes := []testRoute{\n\t\t{"/cmd/:tool/:sub", false},\n\t\t{"/cmd/vet", true},\n\t\t{"/src/*filepath", false},\n\t\t{"/src/*filepathx", true},\n\t\t{"/src/", true},\n\t\t{"/src1/", false},\n\t\t{"/src1/*filepath", true},\n\t\t{"/src2*filepath", true},\n\t\t{"/search/:query", false},\n\t\t{"/search/invalid", true},\n\t\t{"/user_:name", false},\n\t\t{"/user_x", true},\n\t\t{"/user_:name", false},\n\t\t{"/id:id", false},\n\t\t{"/id/:id", true},\n\t}\n\ttestRoutes(t, routes)\n}\n\nfunc TestTreeChildConflict(t *testing.T) {\n\troutes := []testRoute{\n\t\t{"/cmd/vet", false},\n\t\t{"/cmd/:tool/:sub", true},\n\t\t{"/src/AUTHORS", false},\n\t\t{"/src/*filepath", true},\n\t\t{"/user_x", false},\n\t\t{"/user_:name", true},\n\t\t{"/id/:id", false},\n\t\t{"/id:id", true},\n\t\t{"/:id", true},\n\t\t{"/*filepath", true},\n\t}\n\ttestRoutes(t, routes)\n}\n\nfunc TestTreeDupliatePath(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/",\n\t\t"/doc/",\n\t\t"/src/*filepath",\n\t\t"/search/:query",\n\t\t"/user_:name",\n\t}\n\tfor _, route := range routes {\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route, fakeHandler(route))\n\t\t})\n\t\tif recv != nil {\n\t\t\tt.Fatalf("panic inserting route \'%s\': %v", route, recv)\n\t\t}\n\n\t\t// Add again\n\t\trecv = catchPanic(func() {\n\t\t\ttree.addRoute(route, nil)\n\t\t})\n\t\tif recv == nil {\n\t\t\tt.Fatalf("no panic while inserting duplicate route \'%s", route)\n\t\t}\n\t}\n\n\t//printChildren(tree, "")\n\n\tcheckRequests(t, tree, testRequests{\n\t\t{"/", false, "/", nil},\n\t\t{"/doc/", false, "/doc/", nil},\n\t\t{"/src/some/file.png", false, "/src/*filepath", Params{Param{"filepath", "/some/file.png"}}},\n\t\t{"/search/someth!ng+in+ünìcodé", false, "/search/:query", Params{Param{"query", "someth!ng+in+ünìcodé"}}},\n\t\t{"/user_gopher", false, "/user_:name", Params{Param{"name", "gopher"}}},\n\t})\n}\n\nfunc TestEmptyWildcardName(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/user:",\n\t\t"/user:/",\n\t\t"/cmd/:/",\n\t\t"/src/*",\n\t}\n\tfor _, route := range routes {\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route, nil)\n\t\t})\n\t\tif recv == nil {\n\t\t\tt.Fatalf("no panic while inserting route with empty wildcard name \'%s", route)\n\t\t}\n\t}\n}\n\nfunc TestTreeCatchAllConflict(t *testing.T) {\n\troutes := []testRoute{\n\t\t{"/src/*filepath/x", true},\n\t\t{"/src2/", false},\n\t\t{"/src2/*filepath/x", true},\n\t}\n\ttestRoutes(t, routes)\n}\n\nfunc TestTreeCatchAllConflictRoot(t *testing.T) {\n\troutes := []testRoute{\n\t\t{"/", false},\n\t\t{"/*filepath", true},\n\t}\n\ttestRoutes(t, routes)\n}\n\nfunc TestTreeDoubleWildcard(t *testing.T) {\n\tconst panicMsg = "only one wildcard per path segment is allowed"\n\n\troutes := [...]string{\n\t\t"/:foo:bar",\n\t\t"/:foo:bar/",\n\t\t"/:foo*bar",\n\t}\n\n\tfor _, route := range routes {\n\t\ttree := &node{}\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route, nil)\n\t\t})\n\n\t\tif rs, ok := recv.(string); !ok || !strings.HasPrefix(rs, panicMsg) {\n\t\t\tt.Fatalf(`"Expected panic "%s" for route \'%s\', got "%v"`, panicMsg, route, recv)\n\t\t}\n\t}\n}\n\n/*func TestTreeDuplicateWildcard(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/:id/:name/:id",\n\t}\n\tfor _, route := range routes {\n\t\t...\n\t}\n}*/\n\nfunc TestTreeTrailingSlashRedirect(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/hi",\n\t\t"/b/",\n\t\t"/search/:query",\n\t\t"/cmd/:tool/",\n\t\t"/src/*filepath",\n\t\t"/x",\n\t\t"/x/y",\n\t\t"/y/",\n\t\t"/y/z",\n\t\t"/0/:id",\n\t\t"/0/:id/1",\n\t\t"/1/:id/",\n\t\t"/1/:id/2",\n\t\t"/aa",\n\t\t"/a/",\n\t\t"/admin",\n\t\t"/admin/:category",\n\t\t"/admin/:category/:page",\n\t\t"/doc",\n\t\t"/doc/go_faq.html",\n\t\t"/doc/go1.html",\n\t\t"/no/a",\n\t\t"/no/b",\n\t\t"/api/hello/:name",\n\t}\n\tfor _, route := range routes {\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route, fakeHandler(route))\n\t\t})\n\t\tif recv != nil {\n\t\t\tt.Fatalf("panic inserting route \'%s\': %v", route, recv)\n\t\t}\n\t}\n\n\t//printChildren(tree, "")\n\n\ttsrRoutes := [...]string{\n\t\t"/hi/",\n\t\t"/b",\n\t\t"/search/gopher/",\n\t\t"/cmd/vet",\n\t\t"/src",\n\t\t"/x/",\n\t\t"/y",\n\t\t"/0/go/",\n\t\t"/1/go",\n\t\t"/a",\n\t\t"/admin/",\n\t\t"/admin/config/",\n\t\t"/admin/config/permissions/",\n\t\t"/doc/",\n\t}\n\tfor _, route := range tsrRoutes {\n\t\thandler, _, tsr := tree.getValue(route)\n\t\tif handler != nil {\n\t\t\tt.Fatalf("non-nil handler for TSR route \'%s", route)\n\t\t} else if !tsr {\n\t\t\tt.Errorf("expected TSR recommendation for route \'%s\'", route)\n\t\t}\n\t}\n\n\tnoTsrRoutes := [...]string{\n\t\t"/",\n\t\t"/no",\n\t\t"/no/",\n\t\t"/_",\n\t\t"/_/",\n\t\t"/api/world/abc",\n\t}\n\tfor _, route := range noTsrRoutes {\n\t\thandler, _, tsr := tree.getValue(route)\n\t\tif handler != nil {\n\t\t\tt.Fatalf("non-nil handler for No-TSR route \'%s", route)\n\t\t} else if tsr {\n\t\t\tt.Errorf("expected no TSR recommendation for route \'%s\'", route)\n\t\t}\n\t}\n}\n\nfunc TestTreeRootTrailingSlashRedirect(t *testing.T) {\n\ttree := &node{}\n\n\trecv := catchPanic(func() {\n\t\ttree.addRoute("/:test", fakeHandler("/:test"))\n\t})\n\tif recv != nil {\n\t\tt.Fatalf("panic inserting test route: %v", recv)\n\t}\n\n\thandler, _, tsr := tree.getValue("/")\n\tif handler != nil {\n\t\tt.Fatalf("non-nil handler")\n\t} else if tsr {\n\t\tt.Errorf("expected no TSR recommendation")\n\t}\n}\n\nfunc TestTreeFindCaseInsensitivePath(t *testing.T) {\n\ttree := &node{}\n\n\troutes := [...]string{\n\t\t"/hi",\n\t\t"/b/",\n\t\t"/ABC/",\n\t\t"/search/:query",\n\t\t"/cmd/:tool/",\n\t\t"/src/*filepath",\n\t\t"/x",\n\t\t"/x/y",\n\t\t"/y/",\n\t\t"/y/z",\n\t\t"/0/:id",\n\t\t"/0/:id/1",\n\t\t"/1/:id/",\n\t\t"/1/:id/2",\n\t\t"/aa",\n\t\t"/a/",\n\t\t"/doc",\n\t\t"/doc/go_faq.html",\n\t\t"/doc/go1.html",\n\t\t"/doc/go/away",\n\t\t"/no/a",\n\t\t"/no/b",\n\t\t"/Π",\n\t\t"/u/apfêl/",\n\t\t"/u/äpfêl/",\n\t\t"/u/öpfêl",\n\t\t"/v/Äpfêl/",\n\t\t"/v/Öpfêl",\n\t\t"/w/♬",  // 3 byte\n\t\t"/w/♭/", // 3 byte, last byte differs\n\t\t"/w/𠜎",  // 4 byte\n\t\t"/w/𠜏/", // 4 byte\n\t}\n\n\tfor _, route := range routes {\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(route, fakeHandler(route))\n\t\t})\n\t\tif recv != nil {\n\t\t\tt.Fatalf("panic inserting route \'%s\': %v", route, recv)\n\t\t}\n\t}\n\n\t// Check out == in for all registered routes\n\t// With fixTrailingSlash = true\n\tfor _, route := range routes {\n\t\tout, found := tree.findCaseInsensitivePath(route, true)\n\t\tif !found {\n\t\t\tt.Errorf("Route \'%s\' not found!", route)\n\t\t} else if string(out) != route {\n\t\t\tt.Errorf("Wrong result for route \'%s\': %s", route, string(out))\n\t\t}\n\t}\n\t// With fixTrailingSlash = false\n\tfor _, route := range routes {\n\t\tout, found := tree.findCaseInsensitivePath(route, false)\n\t\tif !found {\n\t\t\tt.Errorf("Route \'%s\' not found!", route)\n\t\t} else if string(out) != route {\n\t\t\tt.Errorf("Wrong result for route \'%s\': %s", route, string(out))\n\t\t}\n\t}\n\n\ttests := []struct {\n\t\tin    string\n\t\tout   string\n\t\tfound bool\n\t\tslash bool\n\t}{\n\t\t{"/HI", "/hi", true, false},\n\t\t{"/HI/", "/hi", true, true},\n\t\t{"/B", "/b/", true, true},\n\t\t{"/B/", "/b/", true, false},\n\t\t{"/abc", "/ABC/", true, true},\n\t\t{"/abc/", "/ABC/", true, false},\n\t\t{"/aBc", "/ABC/", true, true},\n\t\t{"/aBc/", "/ABC/", true, false},\n\t\t{"/abC", "/ABC/", true, true},\n\t\t{"/abC/", "/ABC/", true, false},\n\t\t{"/SEARCH/QUERY", "/search/QUERY", true, false},\n\t\t{"/SEARCH/QUERY/", "/search/QUERY", true, true},\n\t\t{"/CMD/TOOL/", "/cmd/TOOL/", true, false},\n\t\t{"/CMD/TOOL", "/cmd/TOOL/", true, true},\n\t\t{"/SRC/FILE/PATH", "/src/FILE/PATH", true, false},\n\t\t{"/x/Y", "/x/y", true, false},\n\t\t{"/x/Y/", "/x/y", true, true},\n\t\t{"/X/y", "/x/y", true, false},\n\t\t{"/X/y/", "/x/y", true, true},\n\t\t{"/X/Y", "/x/y", true, false},\n\t\t{"/X/Y/", "/x/y", true, true},\n\t\t{"/Y/", "/y/", true, false},\n\t\t{"/Y", "/y/", true, true},\n\t\t{"/Y/z", "/y/z", true, false},\n\t\t{"/Y/z/", "/y/z", true, true},\n\t\t{"/Y/Z", "/y/z", true, false},\n\t\t{"/Y/Z/", "/y/z", true, true},\n\t\t{"/y/Z", "/y/z", true, false},\n\t\t{"/y/Z/", "/y/z", true, true},\n\t\t{"/Aa", "/aa", true, false},\n\t\t{"/Aa/", "/aa", true, true},\n\t\t{"/AA", "/aa", true, false},\n\t\t{"/AA/", "/aa", true, true},\n\t\t{"/aA", "/aa", true, false},\n\t\t{"/aA/", "/aa", true, true},\n\t\t{"/A/", "/a/", true, false},\n\t\t{"/A", "/a/", true, true},\n\t\t{"/DOC", "/doc", true, false},\n\t\t{"/DOC/", "/doc", true, true},\n\t\t{"/NO", "", false, true},\n\t\t{"/DOC/GO", "", false, true},\n\t\t{"/π", "/Π", true, false},\n\t\t{"/π/", "/Π", true, true},\n\t\t{"/u/ÄPFÊL/", "/u/äpfêl/", true, false},\n\t\t{"/u/ÄPFÊL", "/u/äpfêl/", true, true},\n\t\t{"/u/ÖPFÊL/", "/u/öpfêl", true, true},\n\t\t{"/u/ÖPFÊL", "/u/öpfêl", true, false},\n\t\t{"/v/äpfêL/", "/v/Äpfêl/", true, false},\n\t\t{"/v/äpfêL", "/v/Äpfêl/", true, true},\n\t\t{"/v/öpfêL/", "/v/Öpfêl", true, true},\n\t\t{"/v/öpfêL", "/v/Öpfêl", true, false},\n\t\t{"/w/♬/", "/w/♬", true, true},\n\t\t{"/w/♭", "/w/♭/", true, true},\n\t\t{"/w/𠜎/", "/w/𠜎", true, true},\n\t\t{"/w/𠜏", "/w/𠜏/", true, true},\n\t}\n\t// With fixTrailingSlash = true\n\tfor _, test := range tests {\n\t\tout, found := tree.findCaseInsensitivePath(test.in, true)\n\t\tif found != test.found || (found && (string(out) != test.out)) {\n\t\t\tt.Errorf("Wrong result for \'%s\': got %s, %t; want %s, %t",\n\t\t\t\ttest.in, string(out), found, test.out, test.found)\n\t\t\treturn\n\t\t}\n\t}\n\t// With fixTrailingSlash = false\n\tfor _, test := range tests {\n\t\tout, found := tree.findCaseInsensitivePath(test.in, false)\n\t\tif test.slash {\n\t\t\tif found { // test needs a trailingSlash fix. It must not be found!\n\t\t\t\tt.Errorf("Found without fixTrailingSlash: %s; got %s", test.in, string(out))\n\t\t\t}\n\t\t} else {\n\t\t\tif found != test.found || (found && (string(out) != test.out)) {\n\t\t\t\tt.Errorf("Wrong result for \'%s\': got %s, %t; want %s, %t",\n\t\t\t\t\ttest.in, string(out), found, test.out, test.found)\n\t\t\t\treturn\n\t\t\t}\n\t\t}\n\t}\n}\n\nfunc TestTreeInvalidNodeType(t *testing.T) {\n\tconst panicMsg = "invalid node type"\n\n\ttree := &node{}\n\ttree.addRoute("/", fakeHandler("/"))\n\ttree.addRoute("/:page", fakeHandler("/:page"))\n\n\t// set invalid node type\n\ttree.children[0].nType = 42\n\n\t// normal lookup\n\trecv := catchPanic(func() {\n\t\ttree.getValue("/test")\n\t})\n\tif rs, ok := recv.(string); !ok || rs != panicMsg {\n\t\tt.Fatalf("Expected panic \'"+panicMsg+"\', got \'%v\'", recv)\n\t}\n\n\t// case-insensitive lookup\n\trecv = catchPanic(func() {\n\t\ttree.findCaseInsensitivePath("/test", true)\n\t})\n\tif rs, ok := recv.(string); !ok || rs != panicMsg {\n\t\tt.Fatalf("Expected panic \'"+panicMsg+"\', got \'%v\'", recv)\n\t}\n}\n\nfunc TestTreeWildcardConflictEx(t *testing.T) {\n\tconflicts := [...]struct {\n\t\troute        string\n\t\tsegPath      string\n\t\texistPath    string\n\t\texistSegPath string\n\t}{\n\t\t{"/who/are/foo", "/foo", `/who/are/\\*you`, `/\\*you`},\n\t\t{"/who/are/foo/", "/foo/", `/who/are/\\*you`, `/\\*you`},\n\t\t{"/who/are/foo/bar", "/foo/bar", `/who/are/\\*you`, `/\\*you`},\n\t\t{"/conxxx", "xxx", `/con:tact`, `:tact`},\n\t\t{"/conooo/xxx", "ooo", `/con:tact`, `:tact`},\n\t}\n\n\tfor _, conflict := range conflicts {\n\t\t// I have to re-create a \'tree\', because the \'tree\' will be\n\t\t// in an inconsistent state when the loop recovers from the\n\t\t// panic which threw by \'addRoute\' function.\n\t\ttree := &node{}\n\t\troutes := [...]string{\n\t\t\t"/con:tact",\n\t\t\t"/who/are/*you",\n\t\t\t"/who/foo/hello",\n\t\t}\n\n\t\tfor _, route := range routes {\n\t\t\ttree.addRoute(route, fakeHandler(route))\n\t\t}\n\n\t\trecv := catchPanic(func() {\n\t\t\ttree.addRoute(conflict.route, fakeHandler(conflict.route))\n\t\t})\n\n\t\tif !regexp.MustCompile(fmt.Sprintf("\'%s\' in new path .* conflicts with existing wildcard \'%s\' in existing prefix \'%s\'", conflict.segPath, conflict.existSegPath, conflict.existPath)).MatchString(fmt.Sprint(recv)) {\n\t\t\tt.Fatalf("invalid wildcard conflict error (%v)", recv)\n\t\t}\n\t}\n}\n',
        }
